+// ============================================================================
+// Import Errors
+// ============================================================================
+
+/// Errors that can occur during module import
+pub const ImportError = error{
+    ModuleNotFound,
+    InitFunctionNotFound,
+    InitFailed,
+    InvalidModule,
+    LoadError,
+    VersionMismatch,
+    OutOfMemory,
